```typescript
import { test, expect } from "@playwright/test";

test.describe("TL;DR Interactive Synergy Diagram", () => {
  test.beforeEach(async ({ page }) => {
    console.log('[E2E:Diagram] Navigating to /tldr');
    await page.goto("/tldr");

    // Scroll diagram into view
    console.log('[E2E:Diagram] Scrolling diagram into view');
    await page.locator('svg[aria-label*="synergy"]').scrollIntoViewIfNeeded();
  });

  test.describe("Basic Rendering", () => {
    test("should display all core tool nodes", async ({ page }) => {
      console.log('[E2E:Diagram] Verifying all nodes visible');

      const diagram = page.locator('svg[aria-label*="synergy"]');
      await expect(diagram).toBeVisible();

      // Check for each core tool node
      const coreTools = ['NTM', 'SLB', 'Mail', 'BV', 'UBS', 'CM', 'CASS'];
      for (const tool of coreTools) {
        console.log(`[E2E:Diagram] Checking for ${tool} node`);
        await expect(diagram.locator(`text=${tool}`)).toBeVisible();
      }

      console.log('[E2E:Diagram] All core tool nodes present');
    });

    test("should display connection lines between tools", async ({ page }) => {
      console.log('[E2E:Diagram] Verifying connection lines');

      const diagram = page.locator('svg[aria-label*="synergy"]');
      const lines = diagram.locator('line, path').filter({ has: page.locator('[stroke]') });

      const lineCount = await lines.count();
      console.log(`[E2E:Diagram] Found ${lineCount} connection lines`);

      expect(lineCount).toBeGreaterThan(5); // Should have multiple connections
      console.log('[E2E:Diagram] Connection lines verified');
    });

    test("should display dynamic core tools count", async ({ page }) => {
      console.log('[E2E:Diagram] Checking dynamic count');

      const countLabel = page.locator('text=/\\d+ Core Tools/');
      await expect(countLabel).toBeVisible();

      const text = await countLabel.textContent();
      console.log(`[E2E:Diagram] Center label: "${text}"`);

      // Verify it's a number followed by "Core Tools"
      expect(text).toMatch(/^\d+ Core Tools$/);
      console.log('[E2E:Diagram] Dynamic count verified');
    });
  });

  test.describe("Hover Interactions", () => {
    test("should highlight node on hover", async ({ page }) => {
      console.log('[E2E:Diagram] Testing node hover');

      const diagram = page.locator('svg[aria-label*="synergy"]');
      const ntmNode = diagram.locator('g').filter({ has: page.locator('text=NTM') });

      // Get initial opacity/style
      const initialStyles = await ntmNode.evaluate((el) => ({
        opacity: getComputedStyle(el).opacity,
        transform: getComputedStyle(el).transform,
      }));
      console.log(`[E2E:Diagram] Initial NTM styles: ${JSON.stringify(initialStyles)}`);

      // Hover
      await ntmNode.hover();
      await page.waitForTimeout(100); // Animation time

      // Check for visual change (scale, opacity, glow, etc.)
      const hoveredStyles = await ntmNode.evaluate((el) => ({
        opacity: getComputedStyle(el).opacity,
        transform: getComputedStyle(el).transform,
      }));
      console.log(`[E2E:Diagram] Hovered NTM styles: ${JSON.stringify(hoveredStyles)}`);

      // At least one property should change
      const hasChange = 
        initialStyles.opacity !== hoveredStyles.opacity ||
        initialStyles.transform !== hoveredStyles.transform;

      expect(hasChange).toBe(true);
      console.log('[E2E:Diagram] Node hover effect verified');
    });

    test("should dim non-connected nodes when one is hovered", async ({ page }) => {
      console.log('[E2E:Diagram] Testing dimming of non-connected nodes');

      const diagram = page.locator('svg[aria-label*="synergy"]');

      // Hover on NTM (which connects to SLB, Mail, CASS)
      const ntmNode = diagram.locator('g').filter({ has: page.locator('text=NTM') });
      await ntmNode.hover();
      await page.waitForTimeout(150);

      // UBS should be dimmed (not directly connected to NTM)
      const ubsNode = diagram.locator('g').filter({ has: page.locator('text=UBS') });
      const ubsOpacity = await ubsNode.evaluate((el) => getComputedStyle(el).opacity);
      console.log(`[E2E:Diagram] UBS opacity when NTM hovered: ${ubsOpacity}`);

      expect(parseFloat(ubsOpacity)).toBeLessThan(1);
      console.log('[E2E:Diagram] Non-connected nodes dimmed');
    });

    test("should highlight connection lines to hovered node", async ({ page }) => {
      console.log('[E2E:Diagram] Testing connection line highlighting');

      const diagram = page.locator('svg[aria-label*="synergy"]');
      const ntmNode = diagram.locator('g').filter({ has: page.locator('text=NTM') });

      await ntmNode.hover();
      await page.waitForTimeout(150);

      // Check for highlighted lines (increased opacity, different stroke, glow filter)
      const highlightedLines = diagram.locator('[data-highlighted="true"], .connection-highlighted');
      const highlightedCount = await highlightedLines.count();
      console.log(`[E2E:Diagram] Highlighted connection count: ${highlightedCount}`);

      // NTM has synergies with SLB, Mail, CASS - should have at least 3 highlighted lines
      expect(highlightedCount).toBeGreaterThanOrEqual(3);
      console.log('[E2E:Diagram] Connection highlighting verified');
    });
  });

  test.describe("Click Navigation", () => {
    test("should scroll to tool card when node is clicked", async ({ page }) => {
      console.log('[E2E:Diagram] Testing click navigation');

      const diagram = page.locator('svg[aria-label*="synergy"]');
      const mailNode = diagram.locator('g').filter({ has: page.locator('text=Mail') });

      // Get initial scroll position
      const initialScroll = await page.evaluate(() => window.scrollY);
      console.log(`[E2E:Diagram] Initial scroll: ${initialScroll}`);

      // Click the Mail node
      await mailNode.click();

      // Wait for smooth scroll
      await page.waitForTimeout(800);

      // Scroll position should have changed
      const newScroll = await page.evaluate(() => window.scrollY);
      console.log(`[E2E:Diagram] Scroll after click: ${newScroll}`);

      expect(newScroll).not.toBe(initialScroll);

      // Mail tool card should be visible in viewport
      const mailCard = page.locator('[data-testid="tool-card"]').filter({ hasText: 'MCP Agent Mail' });
      await expect(mailCard).toBeInViewport();
      console.log('[E2E:Diagram] Tool card scrolled into view');
    });

    test("should highlight target card after navigation", async ({ page }) => {
      console.log('[E2E:Diagram] Testing card highlight after click');

      const diagram = page.locator('svg[aria-label*="synergy"]');
      const bvNode = diagram.locator('g').filter({ has: page.locator('text=BV') });

      await bvNode.click();
      await page.waitForTimeout(800);

      // Card should have highlight state
      const bvCard = page.locator('[data-testid="tool-card"]').filter({ hasText: 'Beads Viewer' });

      // Check for highlight class or ring
      const hasHighlight = await bvCard.evaluate((el) => {
        return el.classList.contains('ring-2') || 
               el.classList.contains('highlighted') ||
               el.getAttribute('data-highlighted') === 'true';
      });

      console.log(`[E2E:Diagram] Card highlight state: ${hasHighlight}`);
      expect(hasHighlight).toBe(true);
      console.log('[E2E:Diagram] Card highlighting verified');
    });

    test("should expand collapsed card after navigation", async ({ page }) => {
      console.log('[E2E:Diagram] Testing auto-expand on click');

      // First, make sure all cards are collapsed
      const collapseButtons = page.getByRole('button', { name: /collapse all/i });
      const collapseCount = await collapseButtons.count();
      for (let i = 0; i < collapseCount; i++) {
        await collapseButtons.nth(i).click();
      }

      const diagram = page.locator('svg[aria-label*="synergy"]');
      const cassNode = diagram.locator('g').filter({ has: page.locator('text=CASS') });

      await cassNode.click();
      await page.waitForTimeout(1000);

      // The CASS card should be expanded
      const cassCard = page.locator('[data-testid="tool-card"]').filter({ hasText: 'Coding Agent Session Search' });
      const expandedContent = cassCard.getByText(/why it's useful/i);
      await expect(expandedContent).toBeVisible();

      console.log('[E2E:Diagram] Card auto-expanded after navigation');
    });
  });

  test.describe("Keyboard Navigation", () => {
    test("should support Tab navigation through nodes", async ({ page }) => {
      console.log('[E2E:Diagram] Testing Tab navigation');

      const diagram = page.locator('svg[aria-label*="synergy"]');
      await diagram.focus();

      // Tab through nodes
      for (let i = 0; i < 3; i++) {
        await page.keyboard.press('Tab');
        const focused = await page.locator(':focus').textContent();
        console.log(`[E2E:Diagram] Tab ${i + 1} focused: ${focused}`);
      }

      // A node should be focused
      const focusedElement = page.locator('svg :focus');
      await expect(focusedElement).toBeVisible();
      console.log('[E2E:Diagram] Tab navigation works');
    });

    test("should navigate on Enter key when node focused", async ({ page }) => {
      console.log('[E2E:Diagram] Testing Enter key navigation');

      const diagram = page.locator('svg[aria-label*="synergy"]');
      const ntmNode = diagram.locator('[role="button"]').first();

      await ntmNode.focus();
      await page.keyboard.press('Enter');
      await page.waitForTimeout(800);

      // Should have scrolled to card
      const ntmCard = page.locator('[data-testid="tool-card"]').filter({ hasText: 'Named Tmux Manager' });
      await expect(ntmCard).toBeInViewport();

      console.log('[E2E:Diagram] Enter key navigation works');
    });
  });

  test.describe("Reduced Motion", () => {
    test("should respect prefers-reduced-motion", async ({ page }) => {
      console.log('[E2E:Diagram] Testing reduced motion');

      await page.emulateMedia({ reducedMotion: 'reduce' });
      await page.goto('/tldr');

      const diagram = page.locator('svg[aria-label*="synergy"]');
      const ntmNode = diagram.locator('g').filter({ has: page.locator('text=NTM') });

      // Hover should still change state but without animation
      await ntmNode.hover();

      // Check that transition duration is 0 or very short
      const transitionDuration = await ntmNode.evaluate((el) => 
        getComputedStyle(el).transitionDuration
      );
      console.log(`[E2E:Diagram] Transition duration: ${transitionDuration}`);

      expect(['0s', '0ms', '0.01ms']).toContain(transitionDuration);
      console.log('[E2E:Diagram] Reduced motion respected');
    });
  });
});
